    63Ôćĺ		}
    64Ôćĺ
    65Ôćĺ		return new SearchData(regex, this.wordSeparators ? getMapForWordSeparators(this.wordSeparators, []) : null, canUseSimpleSearch ? this.searchString : null);
    66Ôćĺ	}
    67Ôćĺ}
