    69Ôćĺexport function isMultilineRegexSource(searchString: string): boolean {
    70Ôćĺ	if (!searchString || searchString.length === 0) {
    71Ôćĺ		return false;
    72Ôćĺ	}
    73Ôćĺ
    74Ôćĺ	for (let i = 0, len = searchString.length; i < len; i++) {
    75Ôćĺ		const chCode = searchString.charCodeAt(i);
    76Ôćĺ
    77Ôćĺ		if (chCode === CharCode.LineFeed) {
    78Ôćĺ			return true;
    79Ôćĺ		}
    80Ôćĺ
    81Ôćĺ		if (chCode === CharCode.Backslash) {
    82Ôćĺ
    83Ôćĺ			// move to next char
    84Ôćĺ			i++;
    85Ôćĺ
    86Ôćĺ			if (i >= len) {
    87Ôćĺ				// string ends with a \
    88Ôćĺ				break;
    89Ôćĺ			}
    90Ôćĺ
    91Ôćĺ			const nextChCode = searchString.charCodeAt(i);
    92Ôćĺ			if (nextChCode === CharCode.n || nextChCode === CharCode.r) {
    93Ôćĺ				return true;
    94Ôćĺ			}
    95Ôćĺ		}
    96Ôćĺ	}
    97Ôćĺ
    98Ôćĺ	return false;
    99Ôćĺ}
