   101Ôćĺexport function createFindMatch(range: Range, rawMatches: RegExpExecArray, captureMatches: boolean): FindMatch {
   102Ôćĺ	if (!captureMatches) {
   103Ôćĺ		return new FindMatch(range, null);
   104Ôćĺ	}
   105Ôćĺ	const matches: string[] = [];
   106Ôćĺ	for (let i = 0, len = rawMatches.length; i < len; i++) {
   107Ôćĺ		matches[i] = rawMatches[i];
   108Ôćĺ	}
   109Ôćĺ	return new FindMatch(range, matches);
   110Ôćĺ}
