   112Ôćĺclass LineFeedCounter {
   113Ôćĺ
   114Ôćĺ	private readonly _lineFeedsOffsets: number[];
   115Ôćĺ
   116Ôćĺ	constructor(text: string) {
   117Ôćĺ		const lineFeedsOffsets: number[] = [];
   118Ôćĺ		let lineFeedsOffsetsLen = 0;
   119Ôćĺ		for (let i = 0, textLen = text.length; i < textLen; i++) {
   120Ôćĺ			if (text.charCodeAt(i) === CharCode.LineFeed) {
   121Ôćĺ				lineFeedsOffsets[lineFeedsOffsetsLen++] = i;
   122Ôćĺ			}
   123Ôćĺ		}
   124Ôćĺ		this._lineFeedsOffsets = lineFeedsOffsets;
   125Ôćĺ	}
   126Ôćĺ
   127Ôćĺ	public findLineFeedCountBeforeOffset(offset: number): number {
   128Ôćĺ		const lineFeedsOffsets = this._lineFeedsOffsets;
   129Ôćĺ		let min = 0;
   130Ôćĺ		let max = lineFeedsOffsets.length - 1;
   131Ôćĺ
   132Ôćĺ		if (max === -1) {
   133Ôćĺ			// no line feeds
   134Ôćĺ			return 0;
   135Ôćĺ		}
   136Ôćĺ
   137Ôćĺ		if (offset <= lineFeedsOffsets[0]) {
   138Ôćĺ			// before first line feed
   139Ôćĺ			return 0;
   140Ôćĺ		}
   141Ôćĺ
   142Ôćĺ		while (min < max) {
   143Ôćĺ			const mid = min + ((max - min) / 2 >> 0);
   144Ôćĺ
   145Ôćĺ			if (lineFeedsOffsets[mid] >= offset) {
   146Ôćĺ				max = mid - 1;
   147Ôćĺ			} else {
   148Ôćĺ				if (lineFeedsOffsets[mid + 1] >= offset) {
   149Ôćĺ					// bingo!
   150Ôćĺ					min = mid;
   151Ôćĺ					max = mid;
   152Ôćĺ				} else {
   153Ôćĺ					min = mid + 1;
   154Ôćĺ				}
   155Ôćĺ			}
   156Ôćĺ		}
   157Ôćĺ		return min + 1;
   158Ôćĺ	}
   159Ôćĺ}
