   165Ôćĺ		if (!searchData) {
   166Ôćĺ			return [];
   167Ôćĺ		}
   168Ôćĺ
   169Ôćĺ		if (searchData.regex.multiline) {
   170Ôćĺ			return this._doFindMatchesMultiline(model, searchRange, new Searcher(searchData.wordSeparators, searchData.regex), captureMatches, limitResultCount);
   171Ôćĺ		}
   172Ôćĺ		return this._doFindMatchesLineByLine(model, searchRange, searchData, captureMatches, limitResultCount);
