   177Ôćĺ	 * We must therefore compensate for the count of \n in case the model is CRLF
   178Ôćĺ	 */
   179Ôćĺ	private static _getMultilineMatchRange(model: TextModel, deltaOffset: number, text: string, lfCounter: LineFeedCounter | null, matchIndex: number, match0: string): Range {
