   187Ôćĺ		}
   188Ôćĺ
   189Ôćĺ		let endOffset: number;
   190Ôćĺ		if (lfCounter) {
   191Ôćĺ			const lineFeedCountBeforeEndOfMatch = lfCounter.findLineFeedCountBeforeOffset(matchIndex + match0.length);
   192Ôćĺ			const lineFeedCountInMatch = lineFeedCountBeforeEndOfMatch - lineFeedCountBeforeMatch;
   193Ôćĺ			endOffset = startOffset + match0.length + lineFeedCountInMatch /* add as many \r as there were \n */;
   194Ôćĺ		} else {
   195Ôćĺ			endOffset = startOffset + match0.length;
   196Ôćĺ		}
