   203Ôćĺ	private static _doFindMatchesMultiline(model: TextModel, searchRange: Range, searcher: Searcher, captureMatches: boolean, limitResultCount: number): FindMatch[] {
   204Ôćĺ		const deltaOffset = model.getOffsetAt(searchRange.getStartPosition());
