   210Ôćĺ
   211Ôćĺ		const result: FindMatch[] = [];
   212Ôćĺ		let counter = 0;
   213Ôćĺ
   214Ôćĺ		let m: RegExpExecArray | null;
   215Ôćĺ		searcher.reset(0);
   216Ôćĺ		while ((m = searcher.next(text))) {
   217Ôćĺ			result[counter++] = createFindMatch(this._getMultilineMatchRange(model, deltaOffset, text, lfCounter, m.index, m[0]), m, captureMatches);
