   258Ôćĺ			const searchString = searchData.simpleSearch;
   259Ôćĺ			const searchStringLen = searchString.length;
   260Ôćĺ			const textLength = text.length;
   261Ôćĺ
   262Ôćĺ			let lastMatchIndex = -searchStringLen;
   263Ôćĺ			while ((lastMatchIndex = text.indexOf(searchString, lastMatchIndex + searchStringLen)) !== -1) {
   264Ôćĺ				if (!wordSeparators || isValidMatch(wordSeparators, text, textLength, lastMatchIndex, searchStringLen)) {
   265Ôćĺ					result[resultLen++] = new FindMatch(new Range(lineNumber, lastMatchIndex + 1 + deltaOffset, lineNumber, lastMatchIndex + 1 + searchStringLen + deltaOffset), null);
   266Ôćĺ					if (resultLen >= limitResultCount) {
   267Ôćĺ						return resultLen;
   268Ôćĺ					}
   269Ôćĺ				}
   270Ôćĺ			}
   271Ôćĺ			return resultLen;
   272Ôćĺ		}
   273Ôćĺ
   274Ôćĺ		const searcher = new Searcher(searchData.wordSeparators, searchData.regex);
   275Ôćĺ		let m: RegExpExecArray | null;
   276Ôćĺ		// Reset regex to search from the beginning
   277Ôćĺ		searcher.reset(0);
   278Ôćĺ		do {
   279Ôćĺ			m = searcher.next(text);
   280Ôćĺ			if (m) {
   281Ôćĺ				result[resultLen++] = createFindMatch(new Range(lineNumber, m.index + 1 + deltaOffset, lineNumber, m.index + 1 + m[0].length + deltaOffset), m, captureMatches);
