   290Ôćĺ	public static findNextMatch(model: TextModel, searchParams: SearchParams, searchStart: Position, captureMatches: boolean): FindMatch | null {
   291Ôćĺ		const searchData = searchParams.parseSearchRequest();
   292Ôćĺ		if (!searchData) {
   293Ôćĺ			return null;
   294Ôćĺ		}
   295Ôćĺ
   296Ôćĺ		const searcher = new Searcher(searchData.wordSeparators, searchData.regex);
   297Ôćĺ
   298Ôćĺ		if (searchData.regex.multiline) {
   299Ôćĺ			return this._doFindNextMatchMultiline(model, searchStart, searcher, captureMatches);
   300Ôćĺ		}
   301Ôćĺ		return this._doFindNextMatchLineByLine(model, searchStart, searcher, captureMatches);
   302Ôćĺ	}
